package com.finance.tracker.transaction;
import com.finance.tracker.security.UserPrincipal; import jakarta.validation.Valid; import java.time.LocalDate; import java.util.*; import org.springframework.format.annotation.DateTimeFormat; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/transactions") public class TransactionController {private final TransactionService service;public TransactionController(TransactionService service){this.service=service;} @GetMapping public List<TransactionService.TransactionResponse> list(@AuthenticationPrincipal UserPrincipal u,@RequestParam(required=false) @DateTimeFormat(iso=DateTimeFormat.ISO.DATE) LocalDate startDate,@RequestParam(required=false) @DateTimeFormat(iso=DateTimeFormat.ISO.DATE) LocalDate endDate,@RequestParam(required=false) String category){return service.list(u.id(),startDate,endDate,category);}@PostMapping @ResponseStatus(HttpStatus.CREATED) public TransactionService.TransactionResponse create(@AuthenticationPrincipal UserPrincipal u,@Valid @RequestBody TransactionService.TransactionRequest r){return service.create(u.id(),r);}@PutMapping("/{id}") public TransactionService.TransactionResponse update(@AuthenticationPrincipal UserPrincipal u,@PathVariable Long id,@Valid @RequestBody TransactionService.TransactionRequest r){return service.update(u.id(),id,r);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@AuthenticationPrincipal UserPrincipal u,@PathVariable Long id){service.delete(u.id(),id);}}
